mapper.select:
SELECT s.submission_id, s.project_id, p.project_name, s.lot_id, l.lot_code, l.lot_name, s.registration_id, s.supplier_enterprise_id, s.supplier_name_snapshot, s.supplier_credit_code, s.status, s.latest_version_no, s.latest_submit_time, s.receipt_no, sv.price_amount, sv.contact_name, sv.contact_phone, sv.file_manifest_json, s.withdraw_time, s.withdraw_reason, s.remark, s.version, s.create_time, s.update_time FROM t_bid_submission s INNER JOIN t_bid_project p ON p.project_id = s.project_id INNER JOIN t_bid_lot l ON l.lot_id = s.lot_id LEFT JOIN t_bid_submission_version sv ON sv.submission_id = s.submission_id AND sv.version_no = s.latest_version_no AND sv.deleted_flag = 0
s.deleted_flag = #{queryForm.deletedFlag} AND p.deleted_flag = 0 AND l.deleted_flag = 0
AND ( p.project_name LIKE CONCAT('%', #{queryForm.keyword}, '%') OR l.lot_name LIKE CONCAT('%', #{queryForm.keyword}, '%') OR l.lot_code LIKE CONCAT('%', #{queryForm.keyword}, '%') OR s.supplier_name_snapshot LIKE CONCAT('%', #{queryForm.keyword}, '%') OR s.supplier_credit_code LIKE CONCAT('%', #{queryForm.keyword}, '%') OR s.receipt_no LIKE CONCAT('%', #{queryForm.keyword}, '%') )
AND s.project_id = #{queryForm.projectId}
AND s.lot_id = #{queryForm.lotId}
AND s.registration_id = #{queryForm.registrationId}
AND s.supplier_enterprise_id = #{queryForm.supplierEnterpriseId}
AND s.status = #{queryForm.status}
ORDER BY s.latest_submit_time DESC, s.create_time DESC, s.submission_id DESC
